import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';

const tags = [
  '⚙️ Mechanical', '⚡ Electrical', '📡 IoT',
  '📟 Embedded', '🤖 Robotics', '💻 Software',
  '🔩 Hardware', '🧊 3D Design',
];

export default function Home({ onNavigate }) {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const w = mount.clientWidth;
    const h = mount.clientHeight;

    // Scene & camera
    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(60, w / h, 0.1, 100);
    camera.position.z = 2.8;

    // Renderer (transparent bg)
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    // Outer wireframe icosahedron (cyan)
    const meshOuter = new THREE.Mesh(
      new THREE.IcosahedronGeometry(1.0, 2),
      new THREE.MeshBasicMaterial({ color: 0x00f5ff, wireframe: true, transparent: true, opacity: 0.18 })
    );
    scene.add(meshOuter);

    // Inner denser icosahedron (purple)
    const meshInner = new THREE.Mesh(
      new THREE.IcosahedronGeometry(0.62, 3),
      new THREE.MeshBasicMaterial({ color: 0xbf00ff, wireframe: true, transparent: true, opacity: 0.22 })
    );
    scene.add(meshInner);

    // Floating particles
    const pCount = 120;
    const pos    = new Float32Array(pCount * 3);
    for (let i = 0; i < pCount; i++) {
      const theta = Math.random() * Math.PI * 2;
      const phi   = Math.acos(2 * Math.random() - 1);
      const r     = 1.1 + Math.random() * 0.55;
      pos[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    const particleGeo = new THREE.BufferGeometry();
    particleGeo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
    const particles = new THREE.Points(
      particleGeo,
      new THREE.PointsMaterial({ color: 0x00f5ff, size: 0.022, transparent: true, opacity: 0.7 })
    );
    scene.add(particles);

    // Orbit rings
    const ring1 = new THREE.Mesh(
      new THREE.TorusGeometry(1.28, 0.003, 8, 120),
      new THREE.MeshBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.25 })
    );
    ring1.rotation.x = Math.PI / 2.8;
    scene.add(ring1);

    const ring2 = new THREE.Mesh(
      new THREE.TorusGeometry(1.18, 0.002, 8, 100),
      new THREE.MeshBasicMaterial({ color: 0xbf00ff, transparent: true, opacity: 0.2 })
    );
    ring2.rotation.x = Math.PI / 5;
    ring2.rotation.z = Math.PI / 4;
    scene.add(ring2);

    // Mouse parallax
    let mx = 0, my = 0;
    const onMouseMove = (e) => {
      const r = mount.getBoundingClientRect();
      mx = ((e.clientX - r.left)  / r.width  - 0.5) * 2;
      my = ((e.clientY - r.top)   / r.height - 0.5) * 2;
    };
    window.addEventListener('mousemove', onMouseMove);

    // Animation loop
    let frameId;
    const clock = new THREE.Clock();
    const animate = () => {
      frameId = requestAnimationFrame(animate);
      const t = clock.getElapsedTime();

      meshOuter.rotation.x = t * 0.09 + my * 0.15;
      meshOuter.rotation.y = t * 0.13 + mx * 0.15;
      meshInner.rotation.x = -t * 0.14;
      meshInner.rotation.y =  t * 0.18;
      particles.rotation.y =  t * 0.06;
      particles.rotation.x =  t * 0.03;
      ring1.rotation.z     =  t * 0.12;
      ring2.rotation.z     = -t * 0.09;

      // Breathing
      const s = 1 + Math.sin(t * 0.8) * 0.025;
      meshOuter.scale.setScalar(s);

      renderer.render(scene, camera);
    };
    animate();

    // Handle resize
    const onResize = () => {
      const nw = mount.clientWidth;
      const nh = mount.clientHeight;
      camera.aspect = nw / nh;
      camera.updateProjectionMatrix();
      renderer.setSize(nw, nh);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(frameId);
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, []);

  return (
    <section className="home-section">

      {/* Left: text */}
      <div className="hero-content">
        <div className="hero-label">// Computer Engineering · IPB University · Bogor</div>

        <h1 className="hero-title">
          Engineer at<br />
          <span className="hero-title-gradient">Every Layer.</span><br />
          Hardware to Code.
        </h1>

        <p className="hero-sub">
          Mechanical · Electrical · IoT · Embedded · Robotics · Software · 3D Design
        </p>

        <p className="hero-desc">
          Naufal Auzan — final-year Computer Engineering student at IPB University
          yang membangun sistem dari komponen fisik hingga aplikasi digital.
          Dari chassis UGV berbasis AI hingga sistem IoT real-time.
        </p>

        <div className="hero-tags">
          {tags.map(t => <span key={t} className="tag">{t}</span>)}
        </div>

        <div className="hero-cta">
          <button className="btn-primary" onClick={() => onNavigate('projects')}>
            View Projects
          </button>
          <button className="btn-outline" onClick={() => onNavigate('contact')}>
            Get In Touch
          </button>
        </div>
      </div>

      {/* Right: Three.js canvas */}
      <div className="hero-3d" ref={mountRef} />

    </section>
  );
}
